      parentTips: [
        {cn:"\u548c\u5b69\u5b50\u4e00\u8d77\u89c2\u5bdf\u590f\u5929\u91cc\u690d\u7269\u7684\u53d8\u5316\uff0c\u9a8c\u8bc1\u8bfe\u6587\u4e2d\u7684\u63cf\u5199",en:"Observe summer plant growth with your child to verify the text\u2019s descriptions"}
      ]
